import os, sys, json, argparse, math
import numpy as np
from collections import deque
import cogniplan_env
from cogniplan_env import ExplorationEnv


def euclidean(p1, p2):
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def build_graph(nodes):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = (n['coords'][0], n['coords'][1])
        coord_to_idx[coord] = i
    adj = [[] for _ in nodes]
    for i, n in enumerate(nodes):
        for nb_coord in n.get('neighbors', []):
            nb_key = (nb_coord[0], nb_coord[1])
            if nb_key in coord_to_idx:
                adj[i].append(coord_to_idx[nb_key])
    return coord_to_idx, adj


def bfs_shortest_path(start_coord, target_coord, coord_to_idx, adj, nodes):
    start_idx = coord_to_idx.get(start_coord)
    target_idx = coord_to_idx.get(target_coord)
    if start_idx is None or target_idx is None:
        return None
    if start_idx == target_idx:
        return []
    parent = [-1] * len(nodes)
    visited = [False] * len(nodes)
    q = deque([start_idx])
    visited[start_idx] = True
    while q:
        u = q.popleft()
        for v in adj[u]:
            if not visited[v]:
                visited[v] = True
                parent[v] = u
                if v == target_idx:
                    path = []
                    while v != start_idx:
                        path.append(v)
                        v = parent[v]
                    path.reverse()
                    return [nodes[i]['coords'] for i in path]
                q.append(v)
    return None


def closest_node_to(pos, nodes):
    min_d = float('inf')
    best = None
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        d = euclidean(pos, coord)
        if d < min_d:
            min_d = d
            best = coord
    return best


def frontier_centroid(frontiers):
    if not frontiers:
        return None
    avg_x = sum(f[0] for f in frontiers) / len(frontiers)
    avg_y = sum(f[1] for f in frontiers) / len(frontiers)
    return (avg_x, avg_y)


def smart_policy(obs, current_node_coord, coord_to_idx, adj, nodes, visited_recent, epsilon):
    """
    Returns (target_node_coord, None) or (None, None) if stuck.
    """
    neighbors = obs.get('neighbors', [])
    if not neighbors:
        return None
    neighbor_set = set(tuple(nb) for nb in neighbors)

    # epsilon-random tie-breaking
    if np.random.random() < epsilon:
        return tuple(np.random.choice([tuple(nb) for nb in neighbors])

    # 1. immediate neighbor with highest utility, not recently visited
    best_util_neighbor = None
    best_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set:
            if coord in visited_recent:
                continue  # skip recently visited
            util = n.get('utility', 0)
            if util > best_util:
                best_util = util
                best_util_neighbor = coord
    if best_util > 0:
        return best_util_neighbor

    # 2. global best utility node via BFS (ignore recently visited)
    target_coord = None
    max_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in visited_recent:
            continue
        util = n.get('utility', 0)
        if util > max_util:
            max_util = util
            target_coord = coord
    if target_coord is not None and max_util > 0:
        path = bfs_shortest_path(current_node_coord, target_coord, coord_to_idx, adj, nodes)
        if path and len(path) > 0:
            next_node = path[0]
            if next_node in neighbor_set:
                return next_node

    # 3. navigate toward frontier centroid
    frontiers = obs.get('frontiers', [])
    if frontiers:
        centroid = frontier_centroid(frontiers)
        nearest_node_to_centroid = closest_node_to(centroid, nodes)
        if nearest_node_to_centroid:
            path = bfs_shortest_path(current_node_coord, nearest_node_to_centroid, coord_to_idx, adj, nodes)
            if path and len(path) > 0:
                next_node = path[0]
                if next_node in neighbor_set:
                    return next_node

    # 4. fallback: nearest unvisited node (not recently visited)
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set and coord not in visited_recent:
            if not n.get('visited', False):
                return coord

    # 5. any neighbor not recently visited
    for nb in neighbors:
        if tuple(nb) not in visited_recent:
            return tuple(nb)

    # 6. last resort: any neighbor
    return tuple(neighbors[0])


def run_episode(env):
    obs = env.reset()
    nodes = obs['nodes']
    robot_pos = obs['robot_pos']
    start_node = closest_node_to(robot_pos, nodes)
    if start_node is None:
        start_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
    current_node = start_node
    visited_recent = deque(maxlen=3)
    visited_recent.append(start_node)
    travel_distance = 0.0
    last_pos = robot_pos
    epsilon = 0.02

    for step in range(128):
        coord_to_idx, adj = build_graph(nodes)
        target = smart_policy(obs, current_node, coord_to_idx, adj, nodes, visited_recent, epsilon)
        if target is None:
            break
        obs, info = env.step(target)
        travel_distance += euclidean(last_pos, obs['robot_pos'])
        last_pos = obs['robot_pos']
        current_node = target
        visited_recent.append(target)
        nodes = obs['nodes']  # nodes may be updated
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics['success'], metrics['explored_rate'], travel_distance


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    data_path = args.data_path
    eval_config_path = os.path.join(data_path, 'eval_config.json')
    with open(eval_config_path, 'r') as f:
        eval_config = json.load(f)

    maps_eval_dir = os.path.join(data_path, 'maps_eval')
    total_episodes = 0
    per_episode = []
    per_type = {}
    success_count = 0
    explored_sum = 0.0
    dist_succ = 0.0

    for env_type in ['room', 'tunnel', 'outdoor']:
        type_dir = os.path.join(maps_eval_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        results = []
        for fname in sorted(os.listdir(type_dir)):
            if not fname.endswith('.png'):
                continue
            map_path = os.path.join(type_dir, fname)
            env = ExplorationEnv(map_path=map_path)
            success, explored_rate, travel_dist = run_episode(env)
            per_episode.append({
                'map_path': os.path.join(env_type, fname),
                'env_type': env_type,
                'success': int(success),
                'travel_distance': travel_dist,
                'explored_rate': explored_rate
            })
            results.append((success, explored_rate, travel_dist))
            total_episodes += 1
            if success:
                success_count += 1
                dist_succ += travel_dist
            explored_sum += explored_rate
        succ_rates = sum(r[0] for r in results) / len(results) if results else 0
        avg_explored = sum(r[1] for r in results) / len(results) if results else 0
        succ_dists = [r[2] for r in results if r[0]]
        avg_dist_type = sum(succ_dists) / len(succ_dists) if succ_dists else 0.0
        per_type[env_type] = {
            'explored_rate': avg_explored,
            'travel_distance': avg_dist_type,
            'success_rate': succ_rates
        }

    output = {
        'explored_rate': explored_sum / total_episodes if total_episodes else 0.0,
        'travel_distance': dist_succ / success_count if success_count else 0.0,
        'success_rate': success_count / total_episodes if total_episodes else 0.0,
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': total_episodes
    }
    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)


if __name__ == '__main__':
    main()
